class Solution:
    def longestPalindrome(self, s: str, t: str) -> int:
        def is_palindrome(s):
            return s == s[::-1]

        max_len = 0
        for i in range(len(s) + 1):
            for j in range(len(t) + 1):
                substring_s = s[:i] + s[j:]
                substring_t = t[:j] + t[i:]
                if is_palindrome(substring_s + substring_t):
                    max_len = max(max_len, len(substring_s + substring_t))
        return max_len
